1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	const CURSE_SURCHARGE = 0.5;
9	const FIRST_INSURANCE_SURCHARGE = 0.1;
10	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
11	const HIGH_ENCHANTMENT_THRESHOLD = 5;
12	
13	export interface QuoteStep {
14	  op: "quote";
15	  items: Item[];
16	}
17	
18	export type Step = QuoteStep;
19	
