22	  steps: Step[];
23	}
24	
25	export interface QuoteResult {
26	  premium: number;
27	}
28	
29	export interface ScenarioResult {
30	  results: QuoteResult[];
31	}
32	
33	const PROCESSING_FEE = 5;
34	
35	const BASE_PREMIUM: Record<string, number> = {
36	  sword: 100,
37	  amulet: 60,
38	  staff: 80,
39	  potion: 40,
40	  rune: 25,
41	  moonstone: 25,
42	};
43	
44	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
45	
46	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
47	const COMPONENT_BLOCK_SIZE = 3;
48	const COMPONENT_BLOCK_PRICE = 60;
49	
50	const groupByType = (items: Item[]): Map<string, Item[]> => {
51	  const groups = new Map<string, Item[]>();
52	  for (const item of items) {
53	    const group = groups.get(item.type) ?? [];
54	    group.push(item);
55	    groups.set(item.type, group);
56	  }
57	  return groups;
58	};
59	
60	const itemSurchargeFactor = (item: Item): number =>
61	  FIRST_INSURANCE_SURCHARGE +
62	  (item.cursed ? CURSE_SURCHARGE : 0) +
63	  ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
64	    ? HIGH_ENCHANTMENT_SURCHARGE
65	    : 0);
66	
67	const itemModifiersFor = (item: Item): number =>
68	  basePremiumFor(item) * itemSurchargeFactor(item);
69	
70	const groupBaseCost = (type: string, group: Item[]): number => {
71	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
72	    return COMPONENT_BLOCK_PRICE;
73	  }
74	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
75	};
76	
77	const groupSubtotal = (type: string, group: Item[]): number =>
78	  groupBaseCost(type, group) +
79	  group.reduce((sum, item) => sum + itemModifiersFor(item), 0);
80	
81	const itemsSubtotal = (items: Item[]): number => {
82	  let total = 0;
83	  for (const [type, group] of groupByType(items)) {
84	    total += groupSubtotal(type, group);
85	  }
86	  return total;
87	};
88	
89	const quote = (items: Item[]): QuoteResult => ({
90	  premium: Math.ceil(itemsSubtotal(items) + PROCESSING_FEE),
91	});
92	
93	export const runScenario = (scenario: Scenario): ScenarioResult => ({
94	  results: scenario.steps.map((step) => quote(step.items)),
95	});
